class AdapterBase(ABC):
    ALLOWED_NAMES: frozenset[str]
    def emit_start(self, tool_name: str, arg_keys: list[str], request_id: str) -> None: ...
    @abstractmethod
    def shape_ok(self, tool_name: str, result: Any) -> Any: ...
    @abstractmethod
    def shape_error(self, tool_name: str, exc: BaseException, **fields: Any) -> Any: ...

class BathosAdapter(AdapterBase):
    ALLOWED_NAMES = frozenset({"mcp.call_start", "mcp.call_end", "mcp.tool_error"})
    def shape_ok(self, tool_name: str, result: Any) -> Any:
        if isinstance(result, dict):
            return {**result, "ok": True, "error_code": None, "error": None, "resolution_hint": None}

class ContemplexAdapter(AdapterBase):
    ALLOWED_NAMES = frozenset({"mcp.call_start", "mcp.call_end", "mcp.tool_error"})
    def shape_ok(self, tool_name: str, result: Any) -> Any:
        return result

def traced_tool(adapter: AdapterBase) -> Callable[[Callable[..., T]], Callable[..., Any]]:
    """Decorator to wrap a FastMCP v2 tool with telemetry.

    Usage:
        @traced_tool(ContemplexAdapter())
        def my_tool(arg: str) -> str:
            return f"result: {arg}"

def timed_command(cmd_name: str | None = None):
    """Decorator to emit CLI command timing events.

    Emits cli.cmd_start before execution and cli.cmd_end after.
    ...example:
        @timed_command()
        def my_command(arg1: str):
            print(f"Running {arg1}")
            return 0

def shape_ok(self, tool_name, result):
    if isinstance(result, dict):
